#include<bits/stdc++.h>
using namespace std;


// applying : observer pattern
// observable : some kind of service provided by app which will send its notification
// say we will take 3 services(observables) for now : service1(deluxe members), service2(premium members)

// when ever some change or new thing happens, these members will get notification automatically regarding that update generated by company, the company/app only need to make the update and call notify function of that service, and tell the notification text to be sent, that it



// =========================MODELS===========================================
// model classes:user and notification
// a notification model class only needs what is the message and user to be sent to, the method on how to be sent(email, push, whatsapp,) will be decied by another manager class

// this way creation and sending of notification can be handled seperately, srp enforced
class Observer {
public:
    virtual string get_mobile() = 0;
    virtual string get_email() = 0;
    virtual string get_name() = 0;
};


class User : public Observer {
private:
    string name;
    string email;
    string mobile;
public:
    // getters and setters
    User (string name, string mobile, string email) {
        this->name = name;
        this->mobile = mobile;
        this->email = email;
    }

    string get_mobile() {
        return this->mobile;
    }

    string get_email() {
        return this->email;
    }

    string get_name() {
        return this->name;
    }
};

// we will use DECORATOR PATTERN TO ADD DIFFERENT ADDITIONALITIES TO NOTIFICATION, LIKE HEADERS, FOOTERS, AND MAKE IT EXTENDIBLE FOR FUTURE
// abstract class

// notification can have other things such as time of creation, source, etc, but for simplicity we have just included a message
class notification {
public:
    virtual string get_message() = 0;
    virtual ~notification() = default;
};

class text_notification : public notification {
private:
    string message;
public:
    text_notification (string message) {
        this->message = message;
    }
    string get_message() {
        return this->message;
    }
};

// decorator has both has a and is a relation with notification class
class Decorator : public notification{
protected:
    notification* noti_child;
    string message;
public:
    virtual string get_message() = 0;
};

class Header_notification : public Decorator {
private:
    string header_title;

public:
    Header_notification(notification* child, string header) {
        this->noti_child = child;
        this->header_title = header;
    }

    string get_message() {
        string child_text = this->noti_child->get_message();
        // attach important header here
        string new_text = this->header_title + "\n" + child_text;
        return new_text;
    }
};

class Footer_notification : public Decorator {
private:
    string footer_title;
public:
    Footer_notification(notification* child, string footer) {
        this->noti_child = child;
        this->footer_title = footer;
    }

    string get_message() {
        string child_text = this->noti_child->get_message();
        // attach important header here
        string new_text = child_text + "\n" + this->footer_title;
        return new_text;
    }
};

