// ===========================NOTIFICATION CHANNEL=============================
// now app/company can create sender according to their needs
class NotificationSender {
public:
    virtual void send(notification& noti, Observer* o) = 0;
    virtual ~NotificationSender() {};
};

class WhatsappSender : public NotificationSender{
public:
    void send(notification& noti, Observer* o) {
        cout << "Whatsapp notification sent..." << endl;
    }
};

class EmailSender : public NotificationSender{
public:
    void send(notification& noti, Observer* o) {
        cout << "Email sent..." << endl;
    }
};

class PushSender : public NotificationSender{
public:
    void send(notification& noti, Observer* o) {
        cout << "Push notification sent..." << endl;
    }
};
