// ============================SINGLETON CLASSES===============================
// singelton casses : logger, databse persistance for storing all notifications (will use eager initialisation)

// logger is fully extendible and singleton class also as one application needs only one logger
class Logger {
public:
    static Logger* log_tool;
    virtual void log(notification* noti, string path) = 0;
};

class File_Logger : public Logger {
private:

    File_Logger () {
        cout << "single File logger created..." << endl;
    }
public:
    static Logger* get_instance() {
        if (Logger::log_tool == nullptr) {
            Logger::log_tool = new File_Logger();

        } else {
            cout << "returning already made instance of Logger" << endl;
        }
        return Logger::log_tool;
    }

    void log(notification* noti, string path) {
        cout<<"message :\n" << noti->get_message() <<endl;
        cout<<"logged to file at:" << path << endl;
    }
};

class Encrypted_Logger : public Logger{
private:

    Encrypted_Logger () {
        cout << "single Encrypted logger created..." << endl;
    }
public:
    static Logger* get_instance() {
        if (Logger::log_tool == nullptr) {
            Logger::log_tool = new Encrypted_Logger();

        } else {
            cout << "returning already made instance og Logger" << endl;
        }
        return Logger::log_tool;
    }

    void log(notification* noti, string path) {
        cout<<"message encrypted and logged to given path..." << endl;
    }

};





// noti will be a model class including, message, noti id, to whom it was send
class DBPersistence {
public:
    static DBPersistence* db;
    virtual void save(notification& noti) = 0;
    virtual ~DBPersistence() = default;
};

class SQLsaver : public DBPersistence {
private:
    SQLsaver () {
        cout << "created single instance of sql saver..." << endl;
    }
public:
    static DBPersistence* get_instance () {
        if (DBPersistence::db==nullptr) {
            DBPersistence::db = new SQLsaver();
        } else {
            cout << "returning already mase instance of DBPersistence..." << endl;
        }
        return DBPersistence::db;
    }

    void save(notification& noti) {
        cout << "saved to sql db" << endl;
    }
};

class MONGODBsaver : public DBPersistence {
private:
    MONGODBsaver () {
        cout << "created single instance of MONGODB saver..." << endl;
    }
public:
    static DBPersistence* get_instance () {
        if (DBPersistence::db==nullptr) {
            DBPersistence::db = new MONGODBsaver();
        } else {
            cout << "returning already mase instance of DBPersistence..." << endl;
        }
        return DBPersistence::db;
    }
    void save(notification& noti) {
        cout << "saved to mongo db" << endl;
    }
};




// eagerly initialise all sigleton classes
Logger* Logger::log_tool = nullptr;
DBPersistence* DBPersistence::db = nullptr;

