// =============================FACTORIES======================================
// factories for creation based on preference
class Logger_Factory {
public:
    static Logger* create_logger(string type) {
        if (type == "File Logger") {
            return File_Logger::get_instance();
        } else if (type == "Encrypted Logger") {
            return Encrypted_Logger::get_instance();
        }
            
        cout << "this type of logger is not supported in this notification system yet ..." << endl;
        return nullptr;
    }
};

class DB_Factory {
public:
    static DBPersistence* create_db(string type) {
        if (type == "SQL") {
            return SQLsaver::get_instance();
        } else if (type == "MONGODB") {
            return MONGODBsaver::get_instance();
        }
            
        cout << "this type of db is not supported in this notification system yet ..." << endl;
        return nullptr;
    }
};

class Notification_Channel_Factory {
public:
    static NotificationSender* initialise_channel(string type) {
        if (type == "Whatsapp") {
            return new WhatsappSender();
        } else if (type == "Email") {
            return new EmailSender();
        } else if (type == "Push"){
            return new PushSender();
        }
        cout << "this type of channel is not supported yet..." << endl;
        return nullptr;
    }
};
