// =====================OBSERVER PATTERN===========================================

class Observable {
protected:
    vector<Observer*> observers;
    NotificationSender* sender;
    
public:
    virtual void add(Observer* o) = 0;
    virtual void remove(Observer* o) = 0;
    virtual void notify(notification& message_about_update)= 0;
};


// ONLY THIS PART IS TO BE MODIFIED BY COMPANY.APP/ REST UNTOUCHED=================
class Deluxe_Service : public Observable {
public:
    Deluxe_Service(string channel_type) {
        this->sender = Notification_Channel_Factory::initialise_channel(channel_type);
    }

    void add(Observer* o) {
        int target_index = -1;
        for (int i = 0; i<this->observers.size(); i++) {
            // /as mobile number and email are unique we can check using any one
            if (o->get_email() == this->observers[i]->get_email()) {
                // targetfound
                target_index = i;
                break;
            }
        }
        if (target_index == -1) {
            this->observers.push_back(o);
            cout << "inserted user to deluxe service" << endl;

        } else {
            cout << "user already in deluxe service" << endl;
        }
        

    }

    void remove(Observer* o) {
        int target_index_to_be_removed = -1;
        for (int i = 0; i<this->observers.size(); i++) {
            // /as mobile number and email are unique we can check using any one
            if (o->get_email() == this->observers[i]->get_email()) {
                // targetfound
                target_index_to_be_removed = i;
                break;
            }
        }
        if (target_index_to_be_removed!=-1) {
            this->observers.erase(this->observers.begin() + target_index_to_be_removed);
            cout << "removed ..." << endl;
        } else {
            cout << "such user is not associated with Deluxe service ..." << endl;
        }
    }

    void notify(notification& noti) {
        // this is the function which is called by app after any update for notifying associated users
        for (Observer* o : this->observers) {
            this->sender->send(noti, o);
        }
    }
    ~Deluxe_Service() {
        delete this->sender;
    }
};

