// this will be our plug and play class that the company/app will interact with

// for app/company to use as interace
class Notification_Service {
private:
    Logger* logger;
    DBPersistence* db;
    string file_path;

    // mp is to be modified by company app, during configuration of services 
    map<string, Observable*> mp = {
        {"Deluxe Service", new Deluxe_Service("Whatsapp")},
        {"Premium Service", new Premium_Service("Email")}
    };
    // this company/app can have multiple services which it can initialise with its own channel
    // because say deluxe member will recieve notification throguh whatsapp
    //ans premium mebers will recieve throguh emails

public:
    Notification_Service(string logger_type, string db_type, string file_path_for_logging) {
        this->logger = Logger_Factory::create_logger(logger_type);
        this->db = DB_Factory::create_db(db_type);
        this->file_path = file_path_for_logging;
        cout << "notification service initialised..." << endl;
    }

    // adder functions, adds observer to a service
    void add_user(string service_name, Observer* o) {
        if (mp.find(service_name) == mp.end()) {
            // first validate that the service should be supported
            cout << "this service is not supported on this app yet ..." << endl;
            return;
        }
        mp[service_name]->add(o);

    }
    // removes user form a service
    void remove_user(string service_name, Observer* o) {
        
        if (mp.find(service_name) == mp.end()) {
            // first validate that the service should be supported
            cout << "this service is not supported on this app yet ..." << endl;
            return;
        }
        mp[service_name]->remove(o);
    }

    void notify(string service_name, notification* noti) {
        if (mp.find(service_name) == mp.end()) {
            // first validate that the service should be supported
            cout << "this service is not supported on this app yet ..." << endl;
            return;
        }

        mp[service_name]->notify(*noti);
        // delegate the logging and storing responsibility
        log_notification(noti);
        store_notification_in_db(noti);

    }

    void log_notification(notification* noti) {
        this->logger->log(noti, this->file_path);
    }

    void store_notification_in_db(notification* noti) {
        this->db->save(*noti);
    }
    ~Notification_Service() {
        delete this->logger;
        delete this->db;
        for (auto &it: this->mp) {
            delete it.second;
        }
    }
};


int main () {
    // in this problem, this is company side and not user side
    // this is a app/company which will use our notification system, 
    

    // (1) initialises service
    Notification_Service service("File Logger", "MONGODB", "c/home/pc/folder_2");


    // (2) now can add observers to any service
    service.add_user("Deluxe Service", new User("Raghu", "9760001059", "c6h6@gmail.com"));
    service.add_user("Premium Service", new User("Rudra", "9760077779", "asr6@gmail.com"));


    // (3) now notification can be created by company according to all the modifications they want, as it is supported by decorator pattern
    notification* noti = new Header_notification(new text_notification("update 1.v.23 is out!!"), "---Update notification ---- ");

    // (4) now this notification can be passed to chosen service to be passed to users, and the notifications sent should be stored and logged, automatically (given in question)
    service.notify("Premium Service", noti);






    // implemented dynamic responsibility allocation successfully : Decorator pattern
    return 0;
}